patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index de3b981a4fe3..3efb81a885fb 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7318,15 +7318,31 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     }
   }

-  // Return true if the loop contains any instructions that are not also part of
-  // the VPlan or are skipped for VPlan-based cost computations. This indicates
-  // that the VPlan contains extra simplifications.
+  // Return true if the loop contains any instructions whose cost is reduced
+  // by the VPlan compared to the legacy cost model. This covers:
+  //  * Instructions not represented by a recipe and not explicitly
+  //    pre-accounted for via legacy precomputation (SkipCostComputation).
+  //  * Instructions that have a recipe but are ignored by the VPlan-based cost
+  //    model (e.g. invariant/predicated instructions present in
+  //    ValuesToIgnore/VecValuesToIgnore) unless they were pre-accounted.
+  // Instructions that were pre-accounted (inductions, exit conditions,
+  // reductions, branches, etc.) are not considered additional simplifications.
+  // Conservatively return true if there exists any instruction in the original
+  // loop that either:
+  //  * does not have a corresponding recipe in the VPlan, or
+  //  * was not explicitly pre-accounted for via legacy precomputation.
+  // This captures any potential simplification performed by the VPlan (recipe
+  // elimination, hoisting, dead code removal, predicate-based ignoring, etc.).
   return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx,
                                     TheLoop](BasicBlock *BB) {
     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
       if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      if (!SeenInstrs.contains(&I))
+        return true; // Instruction removed / simplified.
+      if (!CostCtx.SkipCostComputation.contains(&I))
+        return true; // Instruction cost differs (not pre-accounted explicitly).
+      return false; // Explicitly matched legacy costing.
     });
   });
 }

